    0%, 98% { transform: translate(0); text-shadow: 2px 2px 0 #1a120a, 0 0 10px rgba(200,180,140,0.3); }
    99% { transform: translate(1px, 0); text-shadow: 3px 0 #8b0000, -2px 0 #004466; }
    100% { transform: translate(0); }
