.page-header__title::after {
    content: '';
    position: absolute;
    top: 0;
    left: 0;
    width: 100%;
    height: 100%;
    background: repeating-linear-gradient(0deg, rgba(0,0,0,0.02) 0px, transparent 2px);
    pointer-events: none;
    mix-blend-mode: overlay;
    opacity: 0.5;
}

body {
    position: relative;
    min-height: 100vh;
    overflow-x: hidden;
    background-color: #0c0a06;
}

/* Vignette */
body::before {
    content: '';
    position: fixed;
    top: 0;
    left: 0;
    width: 100vw;
    height: 100vh;
    background: radial-gradient(circle at center, transparent 70%, rgba(0,0,0,0.4) 100%);
    pointer-events: none;
    z-index: 9998;
}

/* Scanlines */
body::after {
    content: '';
    position: fixed;
    top: 0;
    left: 0;
    width: 100vw;
    height: 100vh;
    background: repeating-linear-gradient(0deg, rgba(0,0,0,0.2) 0px, rgba(0,0,0,0.05) 2px, transparent 3px);
    pointer-events: none;
    z-index: 9999;
    mix-blend-mode: multiply;
}

/* Static Overlay – uses html::before to layer above body without extra HTML */
html {
    position: relative;
}

html::before {
    content: '';
    position: fixed;
    top: 0;
    left: 0;
    width: 100vw;
    height: 100vh;
    background: url('data:image/svg+xml,%3Csvg xmlns%3D%22http%3A%2F%2Fwww.w3.org%2F2000%2Fsvg%22 width%3D%22200%22 height%3D%22200%22%3E%3Cfilter id%3D%22noise%22%3E%3CfeTurbulence type%3D%22fractalNoise%22 baseFrequency%3D%220.65%22 numOctaves%3D%223%22 stitchTiles%3D%22stitch%22%2F%3E%3C%2Ffilter%3E%3Crect width%3D%22100%25%22 height%3D%22100%25%22 filter%3D%22url(%23noise)%22 opacity%3D%220.08%22%2F%3E%3C%2Fsvg%3E');
    background-repeat: repeat;
    pointer-events: none;
    z-index: 10000;
    mix-blend-mode: overlay;
}
