@keyframes glitch-border {
    0% { background-position: 0% 50%; }
    50% { background-position: 100% 50%; }
    100% { background-position: 0% 50%; }
}
@keyframes text-flicker {
    0%, 100% { opacity: 1; text-shadow: 2px 0 #ff0000, -2px 0 #00ffff; }
    5% { opacity: 0.8; text-shadow: 3px 0 #00ffff, -3px 0 #ff0000; }
    10% { opacity: 1; text-shadow: 1px 0 #ffff00, -1px 0 #ff00ff; }
    50% { opacity: 0.9; text-shadow: 2px 0 #ff0000, -2px 0 #00ffff; }
}


.fullscreen-content,
.fullscreen-content * {
    background: transparent !important;
    border: none !important;
    box-shadow: none !important;
    outline: none !important;
}

.bg-image {
    width: 100%;
    height: 100%;
    object-fit: cover;
    display: block;
}

.fade-in {
    opacity: 0;
    animation: fade-in 1s ease forwards;
    animation-timeline: view();
    animation-range: entry 0% entry 30%;
}
@supports not (animation-timeline: view()) {
    .fade-in {
        opacity: 1;
        animation: none;
    }
}
