    <div style="position: absolute; top: -4px; left: -4px; right: -4px; bottom: -4px; background: linear-gradient(45deg, #ffffff, #888888, #000000, #aaaaaa, #555555); background-size: 400% 400%; animation: glitch-border 3s infinite; filter: blur(2px) grayscale(1); opacity: 0.7; z-index: 0;"></div>
