    <div style="position: relative; z-index: 2; text-align: center; margin-top: 10px; font-family: 'Courier New', monospace; color: #aaaaaa; font-size: 0.8em; letter-spacing: 6px; text-transform: uppercase; text-shadow: 2px 0 #000000, -2px 0 #ffffff; animation: text-flicker-bw 2s infinite;">This isn’t one of mine…</div>
    <div style="position: relative; z-index: 2; border: 2px solid #2a241c;">
        [[File:AMemoryNowForgotten.jpeg|300px|link=]]
    </div>
    <div style="position: relative; z-index: 2; text-align: center; margin-top: 10px; font-family: 'Courier New', monospace; color: #aaaaaa; font-size: 0.8em; letter-spacing: 6px; text-transform: uppercase; text-shadow: 2px 0 #000000, -2px 0 #ffffff; animation: text-flicker-bw 2s infinite;">[ ACCESS MEMORY ]</div>
</div></div>

|hide=<span style="color: #2b1a0e; background: linear-gradient(to left, #e8d5b5, #c4a67a); z-index: 99999999; position: fixed; top: 1rem; left: 1rem; font-family: 'Courier New', monospace; padding: 8px 16px; border-radius: 2px; cursor: pointer; font-weight: bold; border: 1px solid #5a3e28; box-shadow: 2px 2px 0 #2b1a0e; pointer-events: auto !important;">◀ SINK</span>

